let jobs = [];
const allItems = $input.all();

for (const item of allItems) {
  const data = item.json;

  if (Array.isArray(data)) {
    jobs = jobs.concat(data);
  } else if (Array.isArray(data.jobs)) {
    jobs = jobs.concat(data.jobs);
  } else if (data.position || data.title) {
    jobs.push(data);
  } else {
    const arr = Object.values(data).find(v => Array.isArray(v));
    if (arr) jobs = jobs.concat(arr);
  }
}

if (jobs.length > 0 && jobs[0].legal) {
  jobs = jobs.slice(1);
}

const titleMustHave = [
  'ai ', 'ai-', 'artificial intelligence', 'machine learning', 'ml ',
  'prompt engineer', 'automation', 'llm', 'gpt', 'data scientist',
  'ai analyst', 'ai engineer', 'ai specialist', 'ai strategist',
  'ai ops', 'mlops', 'productiv', 'ai trainer', 'ai data'
];

const seniorKeywords = ['senior', 'lead', 'principal', 'staff', 'director', 
                        'head of', 'vp', 'chief', 'manager'];

const filtered = jobs.filter(job => {
  const title = (job.position || job.title || '').toLowerCase();
  const desc = (job.description || '').toLowerCase();
  const text = title + ' ' + desc;

  const hasAI = titleMustHave.some(kw => title.includes(kw));
  const isSenior = seniorKeywords.some(kw => title.includes(kw));
  const has5Plus = /5\+|6\+|7\+|8\+|10\+/.test(text);

  return hasAI && !isSenior && !has5Plus;
}).slice(0, 15);

let emailBody = '<h2>AI Jobs (0-2 Years Experience)</h2>';
emailBody += '<p>Found ' + filtered.length + ' entry-level AI jobs (from ' + jobs.length + ' total across multiple job boards):</p><hr>';

if (filtered.length > 0) {
  for (let i = 0; i < filtered.length; i++) {
    const job = filtered[i];
    const title = job.position || job.title || 'Job Opening';
    const company = job.company || job.company_name || 'Unknown';
    const link = job.url ? (job.url.startsWith('http') ? job.url : 'https://remoteok.com' + job.url) : (job.apply_url || job.link || '#');
    const desc = (job.description || '').substring(0, 300).replace(/\n/g, ' ').replace(/<[^>]*>/g, '');

    let salaryText = 'Not specified';
    if (job.salary_min > 0 && job.salary_max > 0) {
      salaryText = '$' + job.salary_min + ' - $' + job.salary_max;
    } else if (job.salary) {
      salaryText = job.salary;
    }

    const source = job.company_logo ? 'Remotive' : 'RemoteOK';

    emailBody += '<div style="margin: 20px 0; padding: 15px; border-left: 5px solid #0066cc; background: #f8f9fa;">';
    emailBody += '<h3>' + (i + 1) + '. ' + title + '</h3>';
    emailBody += '<p><strong>Company:</strong> ' + company + '</p>';
    emailBody += '<p><strong>Salary:</strong> ' + salaryText + '</p>';
    emailBody += '<p><strong>Source:</strong> ' + source + '</p>';
    emailBody += '<p>' + desc + '...</p>';
    emailBody += '<p><a href="' + link + '" style="color: #0066cc; font-weight: bold;">Apply Now →</a></p>';
    emailBody += '</div><hr>';
  }
} else {
  emailBody += '<p>No entry-level AI jobs found today across all job boards.</p>';
  emailBody += '<p>Also check: LinkedIn, Wellfound, Y Combinator</p>';
}

emailBody += '<p style="color: #999; font-size: 11px;">Automated by n8n | ' + new Date().toLocaleDateString() + ' | Sources: RemoteOK, Remotive</p>';

return [{
  json: {
    emailBody: emailBody,
    subject: filtered.length > 0 ? filtered.length + ' Entry-Level AI Jobs!' : 'No AI Jobs Today',
    totalJobs: jobs.length,
    filteredCount: filtered.length
  }
}];
